#!/usr/bin/env bash
# newsletter-sponsorship.sh — 赞助 / 广告变现（newsletter sponsorship 销售） SOP walkthrough for 内容创作者经济(Substack / Beehiiv / 公众号 / 知识星球 / 小报童 / Patreon — newsletter 写作 + 订阅制变现 + 受众沉淀 + 个人 IP).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="内容创作者经济(Substack / Beehiiv / 公众号 / 知识星球 / 小报童 / Patreon — newsletter 写作 + 订阅制变现 + 受众沉淀 + 个人 IP)"
WORKFLOW="赞助 / 广告变现（newsletter sponsorship 销售）"

usage() {
  cat <<EOF
newsletter-sponsorship.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./newsletter-sponsorship.sh             # interactive
  ./newsletter-sponsorship.sh --dry-run
  ./newsletter-sponsorship.sh --json
  ./newsletter-sponsorship.sh --explain
  ./newsletter-sponsorship.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "赞助 / 广告变现（newsletter sponsorship 销售）" 工作流。

一句话: 从「我有一定订阅量」到「有付费赞助商、有可复用的销售流程和媒体 kit」。对应 intake 流派 B（ad-supported）的核心子流程，是全生命周期 #1 阶段 3 的一条变现主线。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 平台是聚合者,创作者是租户 — 资产要握在自己手里: newsletter / 创作者经济里,平台(Substack / 公众号)靠控制需求与分发赢,创作者在平台上是租户;真正的资产是「能带走的 email 列表 + 自有域名(海外)/ 私域回流(国内)
  • 「先免费建信任、再变现」的耐心模型: 这一行的资深人默认「受众信任 / 受众深度」是前置资产,变现是它的函数 — 顺序不能反:先把价值无偿给出去、把漏斗顶部做够宽,再谈收费 / 接广告 / 卖课。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**整理数据资产**：订阅数、open rate、CTR、受众画像（行业 / 职级）——这些是定价和招商的底牌。"
  "**定价**：CPM 模型（赞助费 ÷ 订阅数 × 1000）是主流；2025 行业区间约 \$10-75 CPM，B2B 垂直（创始人 \$100+、销售 \$100-200、营销/工程 \$40-60）显著高于泛消费（\$15-35）。小体量常用 flat-rate（< 5000 订阅约 \$50 起）更好管理。"
  "**做媒体 kit**：一页讲清 CPM、unique opens、ad clicks、CPC、受众画像、过往案例——「替广告主省时间」是成交关键。"
  "**主动招商**：小体量靠主动出击——给目标品牌 / 同 niche 已投放别处的广告主发冷邮件，或上 paved / whosponsorsstuff 等赞助市场挂牌。"
  "**交付 + 留案例**：跑完一单，把转化数据（如平均 CTR）做成 case study——下一单议价的最强证据。"
)
declare -a FAILURE_MODES=(
  "**小体量就指望靠广告养活**：赞助定价直接挂订阅规模，没规模没议价权。避免：小体量先靠垂直精准卖单价，规模上来再放量。"
  "**媒体 kit 缺转化数据**：只给订阅数不给 CTR/CPC，广告主无法判断 ROI。避免：kit 里必放过往案例的转化数据。"
  "**赞助位贱卖**：不算 CPM、被砍价。避免:先按 niche 行业 CPM 区间定价,守住底价。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "newsletter-sponsorship-walkthrough"
fi
